// src/pages/DashboardPage.js
import React, { useEffect, useState } from "react";
import { getSessions } from "../utils/firebase";
import "./DashboardPage.css";

function MiniChart({ sessions, field, color, label }) {
  if (!sessions.length) return null;
  const vals = sessions.map((s) => s.metrics?.[field] ?? 0).reverse();
  const max = Math.max(...vals, 1);
  return (
    <div className="mini-chart">
      <span className="mini-chart-label">{label}</span>
      <div className="mini-chart-bars">
        {vals.map((v, i) => (
          <div key={i} className="mini-chart-bar-wrap" title={v}>
            <div
              className="mini-chart-bar"
              style={{ height: `${(v / max) * 100}%`, background: color }}
            />
          </div>
        ))}
      </div>
    </div>
  );
}

export default function DashboardPage({ navigate }) {
  const [sessions, setSessions] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getSessions(20).then((data) => {
      setSessions(data);
      setLoading(false);
    });
  }, []);

  const avg = (field) => {
    if (!sessions.length) return 0;
    return Math.round(sessions.reduce((acc, s) => acc + (s.metrics?.[field] ?? 0), 0) / sessions.length);
  };

  const best = sessions.reduce((b, s) => (!b || (s.metrics?.score ?? 0) > (b.metrics?.score ?? 0)) ? s : b, null);

  return (
    <div className="dashboard-page">
      <nav className="navbar">
        <span className="navbar-logo" onClick={() => navigate("landing")}>CLARIO</span>
        <div className="navbar-links">
          <button className="btn btn-ghost" onClick={() => navigate("landing")}>Home</button>
          <button className="btn btn-primary" onClick={() => navigate("practice")}>🎙️ Practice</button>
        </div>
      </nav>

      <div className="dashboard-inner">
        <div className="dash-header">
          <h1>Your Progress</h1>
          <p>{sessions.length} session{sessions.length !== 1 ? "s" : ""} completed</p>
        </div>

        {loading ? (
          <div className="dash-loading"><div className="spinner" /><p>Loading sessions…</p></div>
        ) : sessions.length === 0 ? (
          <div className="dash-empty card">
            <span className="dash-empty-icon">🎙️</span>
            <h3>No sessions yet</h3>
            <p>Complete your first practice session to see your progress here.</p>
            <button className="btn btn-primary" onClick={() => navigate("practice")}>Start Practicing</button>
          </div>
        ) : (
          <>
            {/* Summary stats */}
            <div className="summary-grid">
              <div className="summary-card card">
                <span className="sum-val" style={{ color: "#a99dff" }}>{sessions.length}</span>
                <span className="sum-label">Sessions</span>
              </div>
              <div className="summary-card card">
                <span className="sum-val" style={{ color: "#4ecca3" }}>{avg("score")}</span>
                <span className="sum-label">Avg Score</span>
              </div>
              <div className="summary-card card">
                <span className="sum-val" style={{ color: "#ffd166" }}>{avg("wpm")}</span>
                <span className="sum-label">Avg WPM</span>
              </div>
              <div className="summary-card card">
                <span className="sum-val" style={{ color: "#fc6c8f" }}>{avg("totalFillers")}</span>
                <span className="sum-label">Avg Fillers</span>
              </div>
            </div>

            {/* Charts */}
            <div className="card charts-row">
              <h3 className="section-h3">📈 Trend (last {sessions.length} sessions)</h3>
              <div className="charts-grid">
                <MiniChart sessions={sessions} field="score"        color="var(--primary)"  label="Score" />
                <MiniChart sessions={sessions} field="wpm"          color="var(--yellow)"   label="WPM" />
                <MiniChart sessions={sessions} field="totalFillers" color="var(--accent)"   label="Fillers" />
              </div>
            </div>

            {/* Best session */}
            {best && (
              <div className="card best-session">
                <div className="best-badge">🏆 Best Session</div>
                <div className="best-row">
                  <div>
                    <p className="best-scenario">{best.scenario}</p>
                    <p className="best-date">{best.date ? new Date(best.date).toLocaleDateString("en-PH", { month: "short", day: "numeric", year: "numeric" }) : "—"}</p>
                  </div>
                  <div className="best-score" style={{ color: "#4ecca3" }}>{best.metrics?.score ?? 0}<span>/100</span></div>
                </div>
                <p className="best-feedback">{best.feedback?.substring(0, 140)}…</p>
              </div>
            )}

            {/* Session history */}
            <div className="history-section">
              <h3 className="section-h3">🗂️ Session History</h3>
              <div className="history-list">
                {sessions.map((s, i) => (
                  <div key={s.id || i} className="history-item card">
                    <div className="hi-left">
                      <span className="hi-scenario">{s.scenario}</span>
                      <span className="hi-date">{s.date ? new Date(s.date).toLocaleDateString("en-PH", { month: "short", day: "numeric" }) : "—"}</span>
                    </div>
                    <div className="hi-metrics">
                      <span className="hi-metric"><b>{s.metrics?.score ?? 0}</b> score</span>
                      <span className="hi-metric"><b>{s.metrics?.wpm ?? 0}</b> WPM</span>
                      <span className="hi-metric"><b>{s.metrics?.totalFillers ?? 0}</b> fillers</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
